import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Info, ArrowUpCircle, ArrowDownCircle, RotateCcw, CreditCard, AlertTriangle, Clock, RefreshCw } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Badge } from "@/components/ui/badge";

const SubscriptionRulesSheet = () => {
  const { t } = useTranslation();
  const [open, setOpen] = useState(false);

  const sections = [
    {
      icon: ArrowUpCircle,
      iconColor: "text-green-600",
      title: t("membership.rules.upgrade.title", "升级 (Upgrade)"),
      badge: t("membership.rules.upgrade.badge", "立即生效"),
      badgeClass: "bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200",
      items: [
        t("membership.rules.upgrade.item1", "升级立即生效，新套餐从当天开始计算"),
        t("membership.rules.upgrade.item2", "Apple 会按比例退还旧套餐剩余天数的费用"),
        t("membership.rules.upgrade.item3", "立即收取新套餐的全额费用"),
        t("membership.rules.upgrade.item4", "示例：VIP1 用了15天后升级 VIP2，退还VIP1剩余约$5，收取VIP2全额$17.99"),
      ],
    },
    {
      icon: ArrowDownCircle,
      iconColor: "text-orange-600",
      title: t("membership.rules.downgrade.title", "降级 (Downgrade)"),
      badge: t("membership.rules.downgrade.badge", "下个周期生效"),
      badgeClass: "bg-orange-100 text-orange-800 dark:bg-orange-900 dark:text-orange-200",
      items: [
        t("membership.rules.downgrade.item1", "降级不会立即生效，当前周期继续享受高等级服务"),
        t("membership.rules.downgrade.item2", "当前周期不退款"),
        t("membership.rules.downgrade.item3", "到期后自动按新等级价格续订"),
        t("membership.rules.downgrade.item4", "多余的完整商店将在降级生效时自动调整为基础版"),
      ],
    },
    {
      icon: RotateCcw,
      iconColor: "text-blue-600",
      title: t("membership.rules.cancelResub.title", "取消与重新订阅"),
      badge: t("membership.rules.cancelResub.badge", "到期后失效"),
      badgeClass: "bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200",
      items: [
        t("membership.rules.cancelResub.item1", "取消订阅 ≠ 立即失效，服务持续到当前周期结束"),
        t("membership.rules.cancelResub.item2", "到期前重新订阅：不会再次收费，只是重新开启自动续订"),
        t("membership.rules.cancelResub.item3", "到期后重新订阅：视为新订阅，重新收取全额费用"),
        t("membership.rules.cancelResub.item4", "订阅过期后60天内重新订阅，不会再次享受免费试用"),
      ],
    },
    {
      icon: CreditCard,
      iconColor: "text-violet-600",
      title: t("membership.rules.billing.title", "续费与账单"),
      badge: null,
      badgeClass: "",
      items: [
        t("membership.rules.billing.item1", "订阅到期前24小时内自动尝试续费"),
        t("membership.rules.billing.item2", "支付失败后 Apple 将在60天内持续尝试扣款"),
        t("membership.rules.billing.item3", "支付失败期间可能暂停服务，修复支付信息后自动恢复"),
        t("membership.rules.billing.item4", "60天后仍失败则订阅彻底过期"),
      ],
    },
    {
      icon: AlertTriangle,
      iconColor: "text-red-600",
      title: t("membership.rules.refund.title", "退款"),
      badge: null,
      badgeClass: "",
      items: [
        t("membership.rules.refund.item1", "退款需联系 Apple 客服申请"),
        t("membership.rules.refund.item2", "退款成功后订阅立即撤销，权限同步取消"),
        t("membership.rules.refund.item3", "升级时旧套餐的退款由 Apple 自动处理"),
      ],
    },
    {
      icon: RefreshCw,
      iconColor: "text-teal-600",
      title: t("membership.rules.restore.title", "恢复购买"),
      badge: null,
      badgeClass: "",
      items: [
        t("membership.rules.restore.item1", "更换设备或重装App后可点击\"恢复购买\"找回订阅"),
        t("membership.rules.restore.item2", "需使用购买时相同的 Apple ID 登录"),
        t("membership.rules.restore.item3", "恢复成功后权限自动同步"),
      ],
    },
  ];

  return (
    <Sheet open={open} onOpenChange={setOpen}>
      <SheetTrigger asChild>
        <Button variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground hover:text-foreground">
          <Info className="h-4.5 w-4.5" />
        </Button>
      </SheetTrigger>
      <SheetContent side="right" className="w-full sm:max-w-md p-0">
        <SheetHeader className="px-5 pt-5 pb-3 border-b">
          <SheetTitle className="text-base flex items-center gap-2">
            <Info className="h-4.5 w-4.5 text-primary" />
            {t("membership.rules.title", "订阅规则说明")}
          </SheetTitle>
        </SheetHeader>
        <ScrollArea className="h-[calc(100vh-80px)]">
          <div className="px-5 py-4 space-y-5">
            {sections.map((section, idx) => {
              const Icon = section.icon;
              return (
                <div key={idx} className="space-y-2.5">
                  <div className="flex items-start gap-2">
                    <Icon className={`h-4 w-4 ${section.iconColor} shrink-0 mt-0.5`} />
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1.5 flex-wrap">
                        <h3 className="font-semibold text-sm break-words">{section.title}</h3>
                        {section.badge && (
                          <Badge className={`text-[10px] px-1.5 py-0 shrink-0 whitespace-nowrap ${section.badgeClass}`}>
                            {section.badge}
                          </Badge>
                        )}
                      </div>
                    </div>
                  </div>
                  <ul className="space-y-1.5 pl-6">
                    {section.items.map((item, i) => (
                      <li key={i} className="text-xs text-muted-foreground leading-relaxed list-disc">
                        {item}
                      </li>
                    ))}
                  </ul>
                  {idx < sections.length - 1 && (
                    <div className="border-b border-border/50 pt-1" />
                  )}
                </div>
              );
            })}

          </div>
        </ScrollArea>
      </SheetContent>
    </Sheet>
  );
};

export default SubscriptionRulesSheet;
